### 2.4 Create `backend/src/services/SessionManager.ts`

```typescript
import { v4 as uuidv4 } from 'uuid';
import * as pty from 'node-pty';
import * as fs from 'fs/promises';
import * as path from 'path';
import { EventEmitter } from 'events';
import type { Session } from '../types';

export class SessionManager extends EventEmitter {
  private sessions: Map<string, Session> = new Map();
  private workspacesDir = path.join(process.cwd(), 'workspaces');

  async createSession(options: { name?: string } = {}): Promise<Session> {
    const id = uuidv4();
    const name = options.name || `session-${id.slice(0, 8)}`;
    const workDir = path.join(this.workspacesDir, id);

    // Create workspace directory
    await fs.mkdir(workDir, { recursive: true });

    // Spawn Claude Code CLI
    const cliProcess = this.spawnClaudeCode(id, workDir);

    const session: Session = {
      id,
      name,
      status: 'starting',
      workingDirectory: workDir,
      cliProcess,
      createdAt: new Date(),
      lastActivity: new Date(),
      commandsExecuted: 0
    };

    this.sessions.set(id, session);

    // Wait for CLI to be ready
    cliProcess.onData((data: string) => {
      if (data.includes('Enter a command') || data.includes('How can I help')) {
        session.status = 'ready';
        this.emit('session:ready', session);
      }
      // Emit all output for dashboard
      this.emit('session:output', { sessionId: id, data });
    });

    this.emit('session:created', session);
    return session;
  }

  private spawnClaudeCode(sessionId: string, workDir: string) {
    const cli = pty.spawn('claude', ['-p', '--output-format', 'json'], {
      name: 'xterm-color',
      cols: 80,
      rows: 24,
      cwd: workDir,
      env: {
        ...process.env,
        CLAUDE_SESSION_ID: sessionId,
        CLAUDE_HOOKS_ENABLED: 'true'
      }
    });

    cli.onExit(({ exitCode }) => {
      const session = this.sessions.get(sessionId);
      if (session) {
        session.status = 'terminated';
        this.emit('session:terminated', { sessionId, exitCode });
      }
    });

    return cli;
  }

  sendCommand(sessionId: string, command: string): void {
    const session = this.sessions.get(sessionId);
    if (!session || session.status === 'terminated') {
      throw new Error(`Session ${sessionId} not found or terminated`);
    }

    session.cliProcess?.write(command + '\n');
    session.status = 'busy';
    session.lastActivity = new Date();
    session.commandsExecuted++;

    this.emit('session:busy', session);
  }

  terminateSession(sessionId: string): void {
    const session = this.sessions.get(sessionId);
    if (!session) return;

    session.cliProcess?.kill();
    session.status = 'terminated';
    this.emit('session:terminated', { sessionId });
  }

  getSession(sessionId: string): Session | undefined {
    return this.sessions.get(sessionId);
  }

  getAllSessions(): Session[] {
    return Array.from(this.sessions.values());
  }

  handleHookEvent(event: any): void {
    const session = this.sessions.get(event.session_id);
    if (!session) return;

    this.emit('session:hook', { sessionId: event.session_id, event });

    // Update status based on hook
    if (event.hook_event_name === 'Stop' && session.status === 'busy') {
      session.status = 'ready';
      this.emit('session:ready', session);
    }
  }
}
```

