```typescript
import { Server as WebSocketServer } from 'ws';
import { SessionManager } from '../services/SessionManager';
import type { Session } from '../types';

export function setupDashboardSocket(wss: WebSocketServer, sessionManager: SessionManager) {
  // Forward session events to all dashboard clients
  sessionManager.on('session:created', (session: Session) => {
    broadcast({ type: 'session:created', session });
  });

  sessionManager.on('session:ready', (session: Session) => {
    broadcast({ type: 'session:updated', session });
  });

  sessionManager.on('session:busy', (session: Session) => {
    broadcast({ type: 'session:updated', session });
  });

  sessionManager.on('session:terminated', ({ sessionId }) => {
    broadcast({ type: 'session:terminated', sessionId });
  });

  sessionManager.on('session:output', ({ sessionId, data }) => {
    broadcast({ type: 'session:output', sessionId, data });
  });

  sessionManager.on('session:hook', ({ sessionId, event }) => {
    broadcast({ type: 'session:hook', sessionId, event });
  });

  wss.on('connection', (ws) => {
    console.log('Dashboard client connected');

    // Send current sessions on connect
    ws.send(JSON.stringify({
      type: 'init',
      sessions: sessionManager.getAllSessions()
    }));

    ws.on('message', (data) => {
      try {
        const msg = JSON.parse(data.toString());
        handleClientMessage(ws, msg, sessionManager);
      } catch (err) {
        console.error('Invalid message:', err);
      }
    });

    ws.on('close', () => {
      console.log('Dashboard client disconnected');
    });
  });

  function broadcast(message: any) {
    wss.clients.forEach((client) => {
      if (client.readyState === 1) { // OPEN
        client.send(JSON.stringify(message));
      }
    });
  }

  function handleClientMessage(ws: any, msg: any, sessionManager: SessionManager) {
    switch (msg.type) {
      case 'subscribe':
        // Handle session-specific subscriptions
        break;
      case 'command':
        sessionManager.sendCommand(msg.sessionId, msg.command);
        break;
      case 'terminate':
        sessionManager.terminateSession(msg.sessionId);
        break;
    }
  }
}
```

### 2.6 Create `backend/src/server.ts`

```typescript
import express from 'express';
import { createServer } from 'http';
import { WebSocketServer } from 'ws';
import { SessionManager } from './services/SessionManager';
import { setupDashboardSocket } from './websocket/DashboardSocket';
import type { CreateSessionRequest, CommandRequest } from './types';

const app = express();
app.use(express.json());

const server = createServer(app);
const wss = new WebSocketServer({ server, path: '/ws' });

const sessionManager = new SessionManager();
setupDashboardSocket(wss, sessionManager);

// Routes

// Create session
app.post('/api/session', async (req, res) => {
  try {
    const options: CreateSessionRequest = req.body;
    const session = await sessionManager.createSession(options);
    res.json(session);
  } catch (err: any) {
    res.status(500).json({ error: err.message });
  }
});

// List sessions
app.get('/api/session', (_req, res) => {
  res.json(sessionManager.getAllSessions());
});

// Get session
app.get('/api/session/:id', (req, res) => {
  const session = sessionManager.getSession(req.params.id);
  if (!session) {
    return res.status(404).json({ error: 'Session not found' });
  }
  res.json(session);
});

// Send command
app.post('/api/session/:id/command', (req, res) => {
  try {
    const { command } = req.body as CommandRequest;
    sessionManager.sendCommand(req.params.id, command);
    res.json({ success: true });
  } catch (err: any) {
    res.status(400).json({ error: err.message });
  }
});

// Terminate session
app.delete('/api/session/:id', (req, res) => {
  sessionManager.terminateSession(req.params.id);
  res.json({ success: true });
});

// Hook events endpoint (for VoiceProxy.hook.ts)
app.post('/api/hooks/event', (req, res) => {
  sessionManager.handleHookEvent(req.body);
  res.json({ received: true });
});

// Health check
app.get('/health', (_req, res) => {
  res.json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    sessions: {
      active: sessionManager.getAllSessions().filter(s => s.status !== 'terminated').length
    }
  });
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`Voice Claude Code backend running on port ${PORT}`);
});
```

