### 4.7 Create `agent/voice_agent.py`

```python
import asyncio
import json
from livekit import rtc
from livekit.agents import AutoSubscribe, JobContext, WorkerOptions, cli
from livekit.plugins import deepgram, cartesia

from .config import Config
from .llm.gemini import IntentRecognizer
import aiohttp

class VoiceAgent:
    def __init__(self):
        self.intent_recognizer = IntentRecognizer()
        self.backend_url = Config.BACKEND_URL
        self.current_session_id = None

    async def send_to_backend(self, intent: str, params: dict):
        """Send intent to backend"""
        async with aiohttp.ClientSession() as session:
            if intent == "createSession":
                async with session.post(
                    f"{self.backend_url}/api/session",
                    json=params
                ) as resp:
                    return await resp.json()
            elif intent == "sendCommand":
                if not self.current_session_id:
                    return {"error": "No active session"}
                async with session.post(
                    f"{self.backend_url}/api/session/{self.current_session_id}/command",
                    json={"command": params.get("command", "")}
                ) as resp:
                    return await resp.json()
            elif intent == "listSessions":
                async with session.get(f"{self.backend_url}/api/session") as resp:
                    return await resp.json()
            elif intent == "switchSession":
                sessions = await self.list_sessions()
                for s in sessions:
                    if s.get("name") == params.get("name"):
                        self.current_session_id = s.get("id")
                        return {"switched_to": s.get("name")}
                return {"error": "Session not found"}

async def entrypoint(ctx: JobContext):
    agent = VoiceAgent()

    # Connect to microphone
    source = rtc.AudioSource(ctx.room)
    stream = AudioStream(source)

    @ctx.room.on("participant_connected")
    def on_participant_connected(participant):
        print(f"Participant connected: {participant.identity}")

    # STT setup
    stt = deepgram.STT()
    stt_stream = stt.stream()

    # TTS setup
    tts = cartesia.TTS()
    tts_stream = tts.stream()

    async def process_audio():
        async for event in stt_stream:
            if event.type == "final_transcript":
                text = event.alternatives[0].text
                print(f"User said: {text}")

                # Recognize intent
                intent_result = await agent.intent_recognizer.recognize(text)
                print(f"Intent: {intent_result}")

                # Execute intent
                response = await agent.send_to_backend(
                    intent_result["intent"],
                    intent_result.get("params", {})
                )

                # Generate response
                response_text = generate_response_text(response)
                tts_stream.push_text(response_text)

    # Start processing
    await asyncio.gather(
        process_audio(),
        handle_room_audio(ctx.room, source, stt_stream),
        play_tts_audio(ctx.room, tts_stream)
    )

def generate_response_text(response: dict) -> str:
    """Generate spoken response from backend response"""
    if "error" in response:
        return f"Sorry, {response['error']}"
    if "id" in response:
        return "Session created and ready"
    if "name" in response and len(response) == 1:
        return f"Switched to {response['name']}"
    return "Done"

async def handle_room_audio(room, source, stt_stream):
    """Handle audio from room"""
    @room.on("track_subscribed")
    def on_track_subscribed(track, publication, participant):
        if track.kind == rtc.TrackKind.KIND_AUDIO:
            async for frame in track:
                stt_stream.push_frame(frame)

async def play_tts_audio(room, tts_stream):
    """Play TTS audio to room"""
    async for audio in tts_stream:
        await room.local_participant.publish_audio(audio)

if __name__ == "__main__":
    cli.run_app(WorkerOptions(entrypoint=entrypoint))
```

